     9→import { PageHeader } from '../components/PageHeader';
    10→import { EmptyState } from '../components/EmptyState';
    11→import { LayoutGrid } from 'lucide-react';
    12→// Masonry removed - using CSS Grid for proper column spanning support
    13→import { DndContext, closestCenter, PointerSensor, useSensor, useSensors, DragOverlay } from '@dnd-kit/core';
    14→import type { DragEndEvent, DragStartEvent } from '@dnd-kit/core';
    15→import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable';
    16→// Centralized widget registry - single source of truth for all widgets
    17→import { getWidgetComponentMap } from '../widgets/Dashboard/WidgetRegistry';
    18→import { logger } from '../services/logger';
    19→import { getContentContrastClass } from '../utils/colorUtils';
    20→
    21→const log = logger.module('Dashboard');
    22→
    23→// Loading fallback - improved skeleton with structure
    24→const WidgetLoader = () => (
    25→  <div className="h-64 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-button overflow-hidden">
    26→    {/* Header skeleton */}
    27→    <div className="px-4 py-3 border-b border-border-light dark:border-border-dark flex items-center justify-between">
    28→      <div className="flex-1">
    29→        <div className="h-4 w-24 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    30→        <div className="h-3 w-16 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse mt-1" />
    31→      </div>
    32→      <div className="flex gap-1">
    33→        <div className="w-6 h-6 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    34→        <div className="w-6 h-6 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    35→      </div>
    36→    </div>
    37→    {/* Content skeleton */}
    38→    <div className="p-4 space-y-3">
    39→      <div className="h-4 w-full bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    40→      <div className="h-4 w-3/4 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    41→      <div className="h-4 w-1/2 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded animate-pulse" />
    42→    </div>
    43→  </div>
    44→);
    45→
    46→// Widget components are now loaded from the centralized WidgetRegistry
    47→// See: src/widgets/Dashboard/WidgetRegistry.ts
    48→
    49→/**
    50→ * Dashboard Page - Personal overview
    51→ */
    52→export const Dashboard: React.FC = () => {
    53→  const [hasData, setHasData] = useState(true);
    54→  const [showBackupReminder, setShowBackupReminder] = useState(false);
    55→  const [showWidgetManager, setShowWidgetManager] = useState(false);
    56→  const [showPresetManager, setShowPresetManager] = useState(false);
    57→  const [showBackgroundCustomizer, setShowBackgroundCustomizer] = useState(false);
    58→  const [activeId, setActiveId] = useState<string | null>(null);
    59→
    60→  // Background settings (persisted to localStorage)
    61→  const [bgSettings, setBgSettings] = useState<BackgroundSettings>(() => {
    62→    const saved = localStorage.getItem('dashboard-background');
    63→    return saved
    64→      ? JSON.parse(saved)
    65→      : { type: 'none', value: '', opacity: 100, blur: 0 };
    66→  });
    67→  const enabledWidgets = useWidgetStore((state) => state.enabledWidgets);
    68→  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
    69→  const reorderWidgets = useWidgetStore((state) => state.reorderWidgets);
    70→
    71→  // Get widget components from centralized registry (memoized to prevent re-creation)
    72→  const WIDGET_COMPONENTS = useMemo(() => getWidgetComponentMap(), []);
    73→
    74→  // Calculate content contrast class based on background luminance
    75→  // This forces appropriate text colors when background contrasts with current theme
    76→  const contentContrastClass = useMemo(() => {
    77→    if (bgSettings.type === 'none' || !bgSettings.value) {
    78→      return '';
    79→    }
    80→    return getContentContrastClass(bgSettings.value) || '';
    81→  }, [bgSettings.type, bgSettings.value]);
    82→
    83→  // Configure drag sensors (require 5px movement to prevent accidental drags)
    84→  const sensors = useSensors(
    85→    useSensor(PointerSensor, {
    86→      activationConstraint: {
    87→        distance: 5,
    88→      },
    89→    })
    90→  );
    91→
    92→  // Handle drag start - track active widget for ghost preview
    93→  const handleDragStart = (event: DragStartEvent) => {
    94→    setActiveId(event.active.id as string);
    95→  };
    96→
    97→  // Handle drag end - reorder widgets
    98→  const handleDragEnd = (event: DragEndEvent) => {
    99→    const { active, over } = event;
   100→
   101→    if (over && active.id !== over.id) {
   102→      const oldIndex = enabledWidgets.indexOf(active.id as string);
   103→      const newIndex = enabledWidgets.indexOf(over.id as string);
   104→
   105→      if (oldIndex !== -1 && newIndex !== -1) {
   106→        const newOrder = [...enabledWidgets];
   107→        const [movedItem] = newOrder.splice(oldIndex, 1);
   108→        newOrder.splice(newIndex, 0, movedItem);
   109→        reorderWidgets(newOrder);
   110→      }
   111→    }
   112→
   113→    setActiveId(null);
   114→  };
   115→
   116→  useEffect(() => {
   117→    document.title = 'Neuman Brain';
   118→
   119→    // Check for hash navigation (#customize-widgets)
   120→    if (window.location.hash === '#customize-widgets') {
   121→      setShowWidgetManager(true);
   122→      // Clear the hash
   123→      window.history.replaceState(null, '', window.location.pathname);
   124→    }
   125→
   126→    // Check if user has any data
   127→    const checkForData = async () => {
   128→      try {
   129→        const keys = await indexedDBService.getAllKeys();
   130→        const hasAnyData = keys.length > 0;
   131→        setHasData(hasAnyData);
   132→
   133→        // Show backup reminder if no data AND not dismissed
   134→        const dismissed = localStorage.getItem('dashboard-backup-reminder-dismissed');
   135→        if (!hasAnyData && !dismissed) {
   136→          setShowBackupReminder(true);
   137→        }
   138→      } catch (error) {
   139→        log.error('Failed to check for data', { error });
   140→      }
   141→    };
   142→
   143→    checkForData();
   144→  }, []);
   145→
   146→  const handleDismissReminder = () => {
   147→    setShowBackupReminder(false);
   148→    localStorage.setItem('dashboard-backup-reminder-dismissed', 'true');
   149→  };
   150→
   151→  const handleBackgroundChange = (newSettings: BackgroundSettings) => {
   152→    setBgSettings(newSettings);
   153→    localStorage.setItem('dashboard-background', JSON.stringify(newSettings));
   154→  };
   155→
   156→  return (
   157→    <div className={`dashboard-page relative isolate ${contentContrastClass}`}>
   158→      {/* Background Layer - z-0 so it appears behind content but visible */}
   159→      {bgSettings.type !== 'none' && (
   160→        <div
   161→          className="dashboard-background fixed inset-0 pointer-events-none z-0"
   162→          style={{
   163→            backgroundImage: bgSettings.value,
   164→            backgroundSize: bgSettings.type === 'image' ? 'cover' : undefined,
   165→            backgroundPosition: bgSettings.type === 'image' ? 'center' : undefined,
   166→            backgroundAttachment: 'fixed',
   167→            opacity: bgSettings.opacity / 100,
   168→            filter: `blur(${bgSettings.blur}px)`,
   169→          }}
   170→        />
   171→      )}
   172→
   173→      <div className="relative z-10">
   174→        <PageHeader>
   175→          <button
   176→            onClick={() => setShowBackgroundCustomizer(true)}
   177→            className="px-3 py-1.5 text-sm bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-lg font-medium transition-colors"
   178→            title="Customize background"
   179→          >
   180→            🎨 Background
   181→          </button>
   182→          <button
   183→            onClick={() => setShowPresetManager(true)}
   184→            className="px-3 py-1.5 text-sm bg-neutral-200 dark:bg-neutral-700 hover:bg-neutral-300 dark:hover:bg-neutral-600 text-text-light-primary dark:text-text-dark-primary rounded-lg font-medium transition-colors"
   185→            title="Manage layout presets"
   186→          >
   187→            📐 Presets
   188→          </button>
   189→        </PageHeader>
   190→      </div>
   191→
   192→      {/* First-Time User Backup Reminder */}
   193→      {showBackupReminder && !hasData && (
   194→        <div className="mb-6 p-6 rounded-lg bg-yellow-50 dark:bg-yellow-900/20 border-2 border-yellow-400 dark:border-yellow-600">
   195→          <div className="flex items-start gap-4">
   196→            <span className="text-3xl">⚠️</span>
   197→            <div className="flex-1">
   198→              <h3 className="text-xl font-bold text-yellow-900 dark:text-yellow-300 mb-2">
   199→                Welcome to Neuman Brain!
   200→              </h3>
   201→              <p className="text-sm text-yellow-800 dark:text-yellow-400 mb-3">
   202→                <strong>Important:</strong> Your data is stored locally in this browser. To protect your work, remember to create regular backups!
