     2→ * Dashboard Widget Store
     3→ *
     4→ * Manages widget state: enabled widgets, order, and settings
     5→ * Persists to localStorage for user preferences
     6→ */
     7→
     8→import { create } from 'zustand';
     9→import { persist } from 'zustand/middleware';
    10→
    11→export interface WidgetSettings {
    12→  refreshRate?: number; // Minutes between auto-refresh
    13→  [key: string]: any; // Widget-specific settings
    14→}
    15→
    16→export interface WidgetState {
    17→  // Enabled widget IDs in display order
    18→  enabledWidgets: string[];
    19→
    20→  // Widget-specific settings
    21→  widgetSettings: Record<string, WidgetSettings>;
    22→
    23→  // Widget sizes (1x, 2x, or 3x width)
    24→  widgetSizes: Record<string, 1 | 2 | 3>;
    25→
    26→  // Actions
    27→  enableWidget: (widgetId: string) => void;
    28→  disableWidget: (widgetId: string) => void;
    29→  reorderWidgets: (newOrder: string[]) => void;
    30→  updateWidgetSettings: (widgetId: string, settings: Partial<WidgetSettings>) => void;
    31→  setWidgetSize: (widgetId: string, size: 1 | 2 | 3) => void;
    32→  isWidgetEnabled: (widgetId: string) => boolean;
    33→  getWidgetSettings: (widgetId: string) => WidgetSettings;
    34→}
    35→
    36→export const useWidgetStore = create<WidgetState>()(
    37→  persist(
    38→    (set, get) => ({
    39→      // Default enabled widgets (core widgets + weathermap only)
    40→      // API widgets (quote, crypto, hackernews, etc.) available in Widget Manager but disabled by default
    41→      enabledWidgets: ['myday', 'weathermap', 'taskssummary', 'tasksquickadd', 'upcomingevents', 'recentnotes'],
    42→
    43→      // Default widget sizes (2-column grid)
    44→      // MyDay: 2x (full row width for today's unified view)
    45→      // WeatherMap: 3x (renders as 2 columns = full row width, locked)
    46→      // Tasks widgets: 1x each (side-by-side in 2 columns)
    47→      // Other core widgets: 1x (1 column = 50% = 2 widgets per row side-by-side)
    48→      widgetSizes: {
    49→        myday: 2,
    50→        weathermap: 3,
    51→        taskssummary: 1,
    52→        tasksquickadd: 1,
    53→        upcomingevents: 1,
    54→        recentnotes: 1,
    55→      },
    56→
    57→      // Default settings
    58→      widgetSettings: {
    59→        quote: { refreshRate: 60 }, // 1 hour
    60→        crypto: { refreshRate: 1 }, // 1 minute
    61→        hackernews: { refreshRate: 15 }, // 15 minutes
    62→        facts: { refreshRate: 60 },
    63→        github: { refreshRate: 60, username: '' },
    64→        weather: { refreshRate: 60 },
    65→        joke: { refreshRate: 30 },
    66→        unsplash: { refreshRate: 60, category: 'nature' },
    67→        pomodoro: { duration: 25 }, // 25 minutes
    68→        reddit: { refreshRate: 15, subreddit: 'programming' },
    69→        devto: { refreshRate: 30 },
    70→        wordofday: { refreshRate: 1440 }, // Once per day
    71→        currency: { refreshRate: 60 },
    72→        worldclock: {},
    73→        ipinfo: { refreshRate: 60 },
    74→        qrcode: {},
    75→        colorpalette: {},
    76→        weathermap: { refreshRate: 60 },
    77→      },
    78→
    79→      enableWidget: (widgetId) => {
    80→        set((state) => {
    81→          if (!state.enabledWidgets.includes(widgetId)) {
    82→            return {
    83→              enabledWidgets: [...state.enabledWidgets, widgetId],
    84→              widgetSizes: { ...state.widgetSizes, [widgetId]: state.widgetSizes[widgetId] || 1 },
    85→            };
    86→          }
    87→          return state;
    88→        });
    89→      },
    90→
    91→      disableWidget: (widgetId) => {
    92→        set((state) => {
    93→          const { [widgetId]: _, ...remainingSizes } = state.widgetSizes;
    94→          return {
    95→            enabledWidgets: state.enabledWidgets.filter((id) => id !== widgetId),
    96→            widgetSizes: remainingSizes,
    97→          };
    98→        });
    99→      },
   100→
   101→      reorderWidgets: (newOrder) => {
   102→        set({ enabledWidgets: newOrder });
   103→      },
   104→
   105→      updateWidgetSettings: (widgetId, settings) => {
   106→        set((state) => ({
   107→          widgetSettings: {
   108→            ...state.widgetSettings,
   109→            [widgetId]: {
   110→              ...state.widgetSettings[widgetId],
   111→              ...settings,
   112→            },
   113→          },
   114→        }));
   115→      },
   116→
   117→      setWidgetSize: (widgetId, size) => {
   118→        set((state) => ({
   119→          widgetSizes: {
   120→            ...state.widgetSizes,
   121→            [widgetId]: size,
   122→          },
   123→        }));
   124→      },
   125→
   126→      isWidgetEnabled: (widgetId) => {
   127→        return get().enabledWidgets.includes(widgetId);
   128→      },
   129→
   130→      getWidgetSettings: (widgetId) => {
   131→        return get().widgetSettings[widgetId] || {};
   132→      },
   133→    }),
   134→    {
   135→      name: 'dashboard-widgets',
   136→      version: 4, // Increment this when you need to trigger migrations
   137→      migrate: (persistedState: any, version: number) => {
   138→        const state = persistedState as WidgetState;
   139→
   140→        // Migration for version 0 -> 1: Add weathermap to enabled widgets if missing
   141→        if (version === 0) {
   142→          if (!state.enabledWidgets.includes('weathermap')) {
   143→            state.enabledWidgets.push('weathermap');
   144→          }
   145→          if (!state.widgetSettings.weathermap) {
   146→            state.widgetSettings.weathermap = { refreshRate: 60 };
   147→          }
   148→        }
   149→
   150→        // Migration for version 1 -> 2: Add widgetSizes if missing, set weathermap to 2x
   151→        if (version < 2) {
   152→          if (!state.widgetSizes) {
   153→            state.widgetSizes = {};
   154→          }
   155→          // Set weathermap to 2x width by default
   156→          if (!state.widgetSizes.weathermap) {
   157→            state.widgetSizes.weathermap = 2;
   158→          }
